import { isUndefined } from 'lodash-es';

import { _accessValue as accessValue } from '@dynatrace/strato-components/core';

import { useColorScale } from './use-color-scale.js';
import { DEFAULT_RANGE_COLOR } from '../constants.js';
import { useMapConfig } from './use-map-config.js';
import {
  type ChoroplethCustomColorProps,
  type ColorParser,
  isLegendColoring,
  type LegendColorLayerProps,
  type LocationColorProps,
} from '../types/coloring.js';
import type {
  Connection,
  ConnectionColorProps,
} from '../types/connection-layer.js';
import { Location } from '../types/location.js';
import {
  isSequentialLegend,
  isThresholdLegend,
} from '../utils/build-scale-from-legend-config.js';

export const useResolveColor = (
  defaultColor: string,
  props:
    | LocationColorProps<never>
    | ConnectionColorProps<never>
    | ChoroplethCustomColorProps<never>
    | LegendColorLayerProps,
  colorParser?: ColorParser,
) => {
  const legendColoring = useColorScale();

  const { legend } = useMapConfig();

  if (!isLegendColoring(props)) {
    return props.color ?? defaultColor;
  }

  const fallbackColor =
    !isUndefined(legend) &&
    (isSequentialLegend(legend) || isThresholdLegend(legend))
      ? DEFAULT_RANGE_COLOR
      : defaultColor;

  let colorLegend: ((item: Record<string, unknown>) => string) | string =
    fallbackColor;

  if (!isUndefined(legendColoring) && !isUndefined(colorParser)) {
    colorLegend = (item: Record<string, unknown>): string => {
      const value = accessValue<number | string>(item, props.valueAccessor);
      if (isUndefined(value)) {
        return fallbackColor;
      }

      const parsedValue =
        typeof value === 'number' ? value + Number.MIN_VALUE : value;

      return colorParser(parsedValue) ?? fallbackColor;
    };
  }

  return colorLegend;
};

export const useResolveLocationColor = <T extends Location>(
  defaultColor: string,
  props: LocationColorProps<T> | LegendColorLayerProps,
  colorParser?: ColorParser,
) => {
  return useResolveColor(defaultColor, props, colorParser) as
    | string
    | ((item: T) => string);
};

export const useResolveConnectionColor = <T extends Connection>(
  defaultColor: string,
  props: ConnectionColorProps<T> | LegendColorLayerProps,
  colorParser?: ColorParser,
) => {
  return useResolveColor(defaultColor, props, colorParser) as
    | string
    | ((item: T) => string);
};

export const useResolveChoroplethColor = <T extends Record<string, unknown>>(
  defaultColor: string,
  props: ChoroplethCustomColorProps<T> | LegendColorLayerProps,
  colorParser?: ColorParser,
) => {
  return useResolveColor(defaultColor, props, colorParser) as
    | string
    | ((item: T) => string);
};
